import React from 'react';

const ExpiryList = ({ rooms = [] }) => {
    // Собираем все продукты из всех комнат в один массив
    const allExpired = rooms.flatMap(room =>
        room.inventory
            .filter(item => item.expiry) // Берем только те, где заполнена дата
            .map(item => ({
                ...item,
                roomId: room.id
            }))
    );

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    return (
        <div className="page-content">
            <h2 className="page-title">🚨 Контроль сроков</h2>

            <div className="expiry-table-container">
                <table className="expiry-table">
                    <thead>
                    <tr>
                        <th>Номер</th>
                        <th>Товар</th>
                        <th>Срок годности</th>
                    </tr>
                    </thead>
                    <tbody>
                    {allExpired.map((item, index) => {
                        const isExpired = new Date(item.expiry) < today;
                        return (
                            <tr key={index} className={isExpired ? 'expired' : 'warning'}>
                                <td><b>{item.roomId}</b></td>
                                <td>{item.name}</td>
                                <td>{item.expiry}</td>
                            </tr>
                        );
                    })}
                    </tbody>
                </table>

                {allExpired.length === 0 && (
                    <div style={{marginTop: '50px', color: '#888'}}>
                        <p>Список пуст.</p>
                        <p style={{fontSize: '12px'}}>Зайдите в любой номер, установите дату продукту и нажмите "Сохранить".</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ExpiryList;
